package be.schaubroeck.lpb.rkm.rekenmotor.rsz;

import be.schaubroeck.lpb.rkm.rekenmotor.AbstractRekenCommand;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenPatronaalPriveRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenPatronaalRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplStatuutDmfappl;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import com.google.common.collect.ImmutableSet;

import java.util.Arrays;
import java.util.Collection;
import java.util.Set;

public class PostControleRsz extends AbstractRekenCommand {


    private static final Set<MoneyKey> RSZ_BIJDRAGE_KEYS = ImmutableSet.<MoneyKey>builder()
            .addAll(Arrays.asList(RekenRszKey.values()))
            .addAll(Arrays.asList(RekenPatronaalRszKey.values()))
            .addAll(Arrays.asList(RekenPatronaalPriveRszKey.values()))
            .build();

    @Override
    protected boolean execute(RekenContext mainContext) {
        LoonElementManager elementManager = mainContext.getUnchecked(RekenChainKey.LOONELEMENT_MANAGER_KEY);
        RegulManager regulManager = mainContext.getUnchecked(RekenChainKey.REGUL_MANAGER_KEY);
        Persoon persoon = mainContext.getUnchecked(RekenChainKey.PERSOON_KEY);
        persoon.getOpdrachten().stream().map(Opdracht::getOpperSlices).flatMap(Collection::stream).forEach(opper -> controleOpper(opper, elementManager, regulManager));
        return CONTINUE_PROCESSING;
    }

    private void controleOpper(Opper opper, LoonElementManager elementManager, RegulManager regulManager) {
        for (LoonElement element : elementManager.getOpperElementen(opper)) {
            if (opper.getRszppo().getStatuutDmfappl() == DmfapplStatuutDmfappl.PERSONEEL_ONDERWIJS_GEEN_DIMONA) {
                for (MoneyKey key : RSZ_BIJDRAGE_KEYS) {
                    check(element, key, regulManager);
                }
            }
        }
    }

    private void check(LoonElement element, MoneyKey key, RegulManager regulManager) {
        Money bedrag = element.getPropertyMoney(key);
        if (bedrag.signum() != 0) {
            regulManager.doRegulException(element.getOpdracht(), Regulkode.DMFA_STATUUT_O_EN_RSZ);
        }

    }


}
